package ru.memearena.scout.api; import org.springframework.context.annotation.Profile; import org.springframework.web.bind.annotation.*; import ru.memearena.meme.infrastructure.MemeRepository; import ru.memearena.scout.application.PredictionResolutionService; import java.time.*; import java.util.*;
@RestController @RequestMapping("/api/v1/admin/scout") public class AdminScoutController{ private final PredictionResolutionService service; public AdminScoutController(PredictionResolutionService s){service=s;} @PostMapping("/resolve") public PredictionResolutionService.Result resolve(){return service.runOnce();} }
@RestController @Profile("local") @RequestMapping("/api/v1/admin/local/scout") class LocalScoutAdminController{ private final MemeRepository memes; private final Clock clock; LocalScoutAdminController(MemeRepository m,Clock c){memes=m;clock=c;} @PostMapping("/memes/{memeId}/make-resolvable") public Map<String,Object> make(@PathVariable UUID memeId){var m=memes.findById(memeId).orElseThrow(); var now=Instant.now(clock); m.makeResolvableForLocal(now.minus(Duration.ofHours(80)),25,20,1600,now); memes.save(m); return Map.of("memeId",memeId,"approvedAt",m.getApprovedAt(),"battlesCount",m.getBattlesCount());} }
